const g = $input.first().json;
const e = g.estado || {};
const p = g.prediccion || {};
const estado = `temperatura=${e.temperatura}C, humedad=${e.humedad}%, gas=${e.gas} (0-4095), persona=${g.persona||'ninguna'}, prediccion_temp_30min=${p.temperatura?p.temperatura.valor:'NA'}, prediccion_gas_30min=${p.gas?p.gas.valor:'NA'}`;

const prompt = `Eres un agente autonomo de una casa inteligente. Analiza el estado y decide una lista de ACCIONES.

ESTADO ACTUAL: ${estado}

REGLAS DE DECISION:
- Si gas>2500 O temperatura>40 => CRITICO: activa buzzer, activa led y envia una notificacion.
- Si gas>1800 (y no critico) => ADVERTENCIA: activa led y registra un evento.
- Si todo normal => solo registra un evento.

FORMATO DE CADA ACCION (en activar_actuador el campo actuador debe ser UN solo valor: buzzer, led o luz; nunca varios juntos):
- {"tipo":"activar_actuador","actuador":"buzzer","estado":true,"razonamiento":"..."}
- {"tipo":"activar_actuador","actuador":"led","estado":true,"razonamiento":"..."}
- {"tipo":"enviar_notificacion","texto":"...","razonamiento":"..."}
- {"tipo":"registrar_evento","evento":"...","razonamiento":"..."}
- {"tipo":"ajustar_umbral","variable":"gas","valor":2000,"razonamiento":"..."}

Genera UNA accion por actuador (si activas buzzer y led, son dos acciones separadas).

EJEMPLO para un estado critico:
{"acciones":[{"tipo":"activar_actuador","actuador":"buzzer","estado":true,"razonamiento":"gas 2700 mayor que 2500"},{"tipo":"activar_actuador","actuador":"led","estado":true,"razonamiento":"alerta visual"},{"tipo":"enviar_notificacion","texto":"Gas critico en la casa","razonamiento":"avisar al usuario"}]}

Responde SOLO JSON con la forma {"acciones":[...]}.`;
return [{ json: { model:'llama3.2:3b', prompt: prompt, stream:false, format:'json', options:{ temperature:0, num_predict:400 } } }];

const resp = $input.first().json.response;
let acciones = [];
try { const parsed = JSON.parse(resp); acciones = parsed.acciones || []; } catch (e) {}
if (!Array.isArray(acciones) || acciones.length === 0) {
  acciones = [{ tipo:'registrar_evento', evento:'sin acciones o respuesta invalida', razonamiento:'fallback' }];
}
// descarta actuadores mal formados (p.ej. el placeholder literal)
const VALIDOS = ['buzzer','led','luz'];
acciones = acciones.filter(a => a.tipo !== 'activar_actuador' || VALIDOS.includes(a.actuador));
return acciones.map(a => ({ json: a }));
